tool.command:
@CMD_UNZIP_ZARR@
mkdir -p output_dir &&
## Determine the SpatialData directory name SDATA_DIR=\$(find . -maxdepth 1 -name "*.zarr" -type d | head -n 1) &&
## Run aggregation sopa aggregate "\${SDATA_DIR}" #if str($aggregate_options.aggregate_genes) == 'yes' --aggregate-genes #end if #if str($aggregate_options.aggregate_channels) == 'yes' --aggregate-channels #end if #if $filtering.min_transcripts --min-transcripts $filtering.min_transcripts #end if #if $filtering.min_intensity_ratio --min-intensity-ratio $filtering.min_intensity_ratio #end if #if str($advanced.shapes_key) != '' --shapes-key '$advanced.shapes_key' #end if #if str($advanced.table_name) != '' --table-name '$advanced.table_name' #end if #if $advanced.expand_radius_ratio --expand-radius-ratio $advanced.expand_radius_ratio #end if #if $advanced.min_area_um2 --min-area $advanced.min_area_um2 #end if &&
## Move to output directory mv "\${SDATA_DIR}" output_dir/ &&
@CMD_ZIP_ZARR@
